     asx_status s;
     uint32_t i;
     int first;

     if (snap == NULL || out == NULL) return ASX_E_INVALID_ARGUMENT;
+    s = validate_snapshot_counts(snap);
+    if (s != ASX_OK) return s;

     s = asx_codec_buffer_append_char(out, '{');
     if (s != ASX_OK) return s;
